/* ═══════════════════════════════════════════════════════════════
   LandingPage.tsx
   ═══════════════════════════════════════════════════════════════ */
import React from 'react';
import { useNavigate } from 'react-router-dom';
import { useProjects } from '../context/ProjectsContext';

export default function LandingPage() {
  const navigate = useNavigate();
  const { createNewProject } = useProjects();

  function handleStart() {
    const project = createNewProject();
    navigate(`/projects/${project.id}`);
  }

  function CloudMonHeroSVG() {
  return (
    <div className="w-full max-w-4xl mx-auto rounded-3xl overflow-hidden bg-white border border-slate-200 shadow-2xl p-4">
      <svg
        viewBox="0 0 800 500"
        xmlns="http://www.w3.org/2000/svg"
        className="w-full h-auto"
      >
        <defs>
          <filter id="glow-green" x="-20%" y="-20%" width="140%" height="140%">
            <feGaussianBlur stdDeviation="4" result="blur" />
            <feComposite in="SourceGraphic" in2="blur" operator="over" />
          </filter>

          <style>
            {`
              @keyframes slideFlow {
                to { stroke-dashoffset: -20; }
              }

              /* Monolith Disappear */
              @keyframes monolithFade {
                0%, 20% { opacity: 1; transform: scale(1); }
                40%, 100% { opacity: 0.1; transform: scale(0.9); }
              }

              /* Microservices Appear */
              @keyframes microservicePop {
                0%, 40% { opacity: 0; transform: scale(0.5) translate(0, 0); }
                60%, 100% { opacity: 1; transform: scale(1); }
              }

              /* Metrics Shift */
              @keyframes costDrop {
                0%, 40% { width: 160px; fill: #EF4444; }
                60%, 100% { width: 60px; fill: #10B981; }
              }
              @keyframes throughputRise {
                0%, 40% { width: 40px; }
                60%, 100% { width: 160px; }
              }

              .monolith { animation: monolithFade 8s ease-in-out infinite; transform-origin: 220px 250px; }
              .micro { animation: microservicePop 8s ease-in-out infinite; transform-origin: center; }
              .cost-bar { animation: costDrop 8s ease-in-out infinite; }
              .throughput-bar { animation: throughputRise 8s ease-in-out infinite; }

              .flow-path {
                stroke-dasharray: 5, 5;
                animation: slideFlow 1s linear infinite;
              }

              .label-text { font-family: ui-sans-serif, system-ui, sans-serif; font-weight: 700; }
            `}
          </style>
        </defs>

        {/* Subtle Background Grid */}
        <rect width="800" height="500" fill="#F8FAFC" />
        <g opacity="0.1" stroke="#64748B" strokeWidth="1">
          {Array.from({ length: 20 }).map((_, i) => (
            <line key={i} x1={i * 40} y1="0" x2={i * 40} y2="500" />
          ))}
          {Array.from({ length: 13 }).map((_, i) => (
            <line key={i} x1="0" y1={i * 40} x2="800" y2={i * 40} />
          ))}
        </g>

        {/* Traffic Ingress */}
        <g transform="translate(40, 250)">
          <circle cx="0" cy="0" r="4" fill="#3B82F6" />
          <path d="M 0 0 L 100 0" stroke="#3B82F6" strokeWidth="2" className="flow-path" />
          <text x="0" y="-15" fill="#64748B" fontSize="10" className="label-text">INCOMING REQUESTS</text>
        </g>

        {/* =========================================
            ARCHITECTURE TRANSFORMATION AREA
            ========================================= */}

        {/* MONOLITH (Initial State) */}
        <g className="monolith">
          <rect x="150" y="150" width="140" height="200" rx="12" fill="white" stroke="#CBD5E1" strokeWidth="2" />
          <rect x="165" y="165" width="110" height="170" rx="6" fill="#F1F5F9" />
          <text x="220" y="245" textAnchor="middle" fill="#475569" fontSize="12" className="label-text">MONOLITHIC</text>
          <text x="220" y="260" textAnchor="middle" fill="#94A3B8" fontSize="10" className="label-text">API SERVER</text>

          {/* Connection to Exit */}
          <path d="M 290 250 L 500 250" stroke="#CBD5E1" strokeWidth="2" strokeDasharray="4 4" />
        </g>

        {/* MICROSERVICES (End State) */}
        <g>
          {/* Node 1 */}
          <g className="micro" style={{ animationDelay: '0s' }}>
            <rect x="350" y="120" width="100" height="60" rx="10" fill="white" stroke="#10B981" strokeWidth="2" filter="url(#glow-green)" />
            <text x="400" y="155" textAnchor="middle" fill="#065F46" fontSize="10" className="label-text">AUTH SERVICE</text>
            <path d="M 140 250 Q 200 250 350 150" stroke="#10B981" strokeWidth="2" fill="none" className="flow-path" />
          </g>

          {/* Node 2 */}
          <g className="micro" style={{ animationDelay: '0.2s' }}>
            <rect x="350" y="220" width="100" height="60" rx="10" fill="white" stroke="#10B981" strokeWidth="2" filter="url(#glow-green)" />
            <text x="400" y="255" textAnchor="middle" fill="#065F46" fontSize="10" className="label-text">PAYMENT API</text>
            <path d="M 140 250 L 350 250" stroke="#10B981" strokeWidth="2" fill="none" className="flow-path" />
          </g>

          {/* Node 3 */}
          <g className="micro" style={{ animationDelay: '0.4s' }}>
            <rect x="350" y="320" width="100" height="60" rx="10" fill="white" stroke="#10B981" strokeWidth="2" filter="url(#glow-green)" />
            <text x="400" y="355" textAnchor="middle" fill="#065F46" fontSize="10" className="label-text">NOTIFS</text>
            <path d="M 140 250 Q 200 250 350 350" stroke="#10B981" strokeWidth="2" fill="none" className="flow-path" />
          </g>
        </g>

        {/* Database Output */}
        <g transform="translate(550, 200)">
          <path d="M 0 20 Q 40 0 80 20 L 80 80 Q 40 100 0 80 Z" fill="white" stroke="#E2E8F0" strokeWidth="2" />
          <text x="40" y="60" textAnchor="middle" fill="#64748B" fontSize="10" className="label-text">SHARED DB</text>

          {/* Output Flows */}
          <path d="M -100 -50 L 0 30" stroke="#E2E8F0" strokeWidth="2" strokeDasharray="4 4" fill="none" />
          <path d="M -100 50 L 0 50" stroke="#E2E8F0" strokeWidth="2" strokeDasharray="4 4" fill="none" />
          <path d="M -100 150 L 0 70" stroke="#E2E8F0" strokeWidth="2" strokeDasharray="4 4" fill="none" />
        </g>

        {/* =========================================
            METRICS CARD (The Impact)
            ========================================= */}
        <g transform="translate(520, 320)">
          <rect width="240" height="140" rx="20" fill="white" stroke="#F1F5F9" strokeWidth="1" style={{ filter: 'drop-shadow(0 10px 15px rgba(0,0,0,0.05))' }} />

          <text x="20" y="35" fill="#0F172A" fontSize="14" className="label-text">Flow Performance</text>

          {/* Metric 1: Throughput */}
          <g transform="translate(20, 60)">
            <text x="0" y="0" fill="#64748B" fontSize="10" className="label-text">THROUGHPUT (REQ/S)</text>
            <rect x="0" y="8" width="200" height="8" rx="4" fill="#F1F5F9" />
            <rect x="0" y="8" width="40" height="8" rx="4" fill="#3B82F6" className="throughput-bar" />
          </g>

          {/* Metric 2: Infrastructure Cost */}
          <g transform="translate(20, 105)">
            <text x="0" y="0" fill="#64748B" fontSize="10" className="label-text">INFRASTRUCTURE COST</text>
            <rect x="0" y="8" width="200" height="8" rx="4" fill="#F1F5F9" />
            <rect x="0" y="8" width="160" height="8" rx="4" fill="#EF4444" className="cost-bar" />
          </g>
        </g>

        {/* Badge: Modernization */}
        <g transform="translate(620, 40)">
           <rect width="140" height="30" rx="15" fill="#F0FDF4" stroke="#BBF7D0" />
           <circle cx="20" cy="15" r="4" fill="#10B981" />
           <text x="35" y="19" fill="#166534" fontSize="10" className="label-text">Optimization Live</text>
        </g>
      </svg>
    </div>
  );
}

  return (
    <div className="page landing">
      <div className="hero">
        <div className="hero-copy">
          <span className="hero-kicker">CloudMon</span>
          <h1>Visualize your architecture and see what your decisions actually mean in practise.</h1>
          <p>
            There have always been back-of-the-envolope estimations and intuitions that drive architecture design. 
            But now, you can actually visualize your architecture and estiamte the traffic it can handle, what bottlenecks you have, what the estimated cost might be.
          </p>
          <p><b>Considering a desing change?</b></p>
          <p><b>Considering using AWS EC2 instead of Azure VMs?</b></p>
          <p></p>
          <div className="hero-actions">
            <button className="btn-primary" onClick={handleStart}>
              Create a project
            </button>
            <button className="btn-secondary" onClick={() => navigate('/projects')}>
              Browse projects
            </button>
          </div>
        </div>
        <div className="hero-panel">
          <div className="panel-card">
            <h3>Architecture first</h3>
            <p>Sketch components and their connections without extra data detail.</p>
          </div>
          <div className="panel-card">
            <h3>Request-by-request</h3>
            <p>
              Every request starts from your base architecture. Evolve flows
              request-by-request.
            </p>
          </div>
          <div className="panel-card">
            <h3>Cloud cost comparison</h3>
            <p>See AWS, GCP and Azure costs side-by-side in the analysis panel.</p>
          </div>
        </div>
      </div>
      <CloudMonHeroSVG />
    </div>

  );
}
